import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Movie {
  title: string;
  rating: number;
  genre: string;
  runtime: number;
}

interface MovieData {
  topPicks: Movie[];
}

export default function Widget() {
  const movieData = response.data as MovieData;
  const { topPicks } = movieData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#333', color: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: response.meta.primaryColor }}>
            Top Movie Picks
          </Typography>
          {topPicks.map((movie, index) => (
            <Box key={index} sx={{ borderBottom: '1px solid #444', pb: 1, mb: 1 }}>
              <Typography variant="body1" fontWeight={600}>
                {movie.title}
              </Typography>
              <Stack direction="row" spacing={0.5} alignItems="center" sx={{ mt: 0.5 }}>
                <Chip label={`Rating: ${movie.rating}`} sx={{ fontSize: '11px', bgcolor: response.meta.accentColor, color: '#000' }} />
                <Chip label={movie.genre} sx={{ fontSize: '11px', bgcolor: '#555', color: '#FFF' }} />
                <Chip label={`${movie.runtime} min`} sx={{ fontSize: '11px', bgcolor: '#555', color: '#FFF' }} />
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
